I sorted it - for anyone who comes across this this was my solution

```javascript
const chunkNameManager = () => {
  const chunks = [];

  const calcChunkName = (chunk, ext = 'js') => {
    const chunkIndex = chunks.findIndex((c) => c.id === chunk.id && c.hash === chunk.hash);
    const chunkExists = chunkIndex > -1;

    let name = getChunkName(chunk.name, ext);

    // If there is no chunk name
    if (!chunk.name) {
      if (chunkExists) {
        name = getChunkName(chunkIndex, ext);
      } else {
        name = getChunkName(chunks.length, ext);
        // Add to the array
        chunks.push(chunk);
      }
    }

    return name;
  };

  return {
    calcChunkName,
  };
};
```

