          Object.assign(plugin.options, {
            filename: (pathData) => {
              const { chunk } = pathData;

              // [name].chunk.css | [x].chunk.css
              return cssChunkManager.calcChunkName(chunk, 'css');
            },
          });
        }

const jsChunkManager = utils.chunkNameManager();

newConfig.output = {
        ...newConfig.output,
        filename: (pathData) => {
          const { chunk } = pathData;

          // [name].chunk.js | [x].chunk.js
          return jsChunkManager.calcChunkName(chunk, 'js');
        },
      };
```

