After some digging, I found a solution with the `ExternalsPlugin`: 

```js
// webpack.config.mjs
import webpack from 'webpack';

const CSS_EXT_REGEX = /\.(sa|sc|c)ss$/;

export default {
  // ...
  plugins: [
    // Prevent absolute URLs starting with a `/` from being resolved by Webpack in Sass or CSS files
    new webpack.ExternalsPlugin(
      "module",
      ({ context, request, dependencyType, contextInfo }, callback) => {
        if (
          dependencyType === "url" &&
          request.startsWith("/") &&
          CSS_EXT_REGEX.test(contextInfo.issuer)
        ) {
          return callback(null, `asset ${request}`);
        }

        callback();
      },
    ),
  ],
};

```

